#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16
#define ETA 0.3f
#define MOMENTUM 0.3f

float squash(float x)
{
    return 1.0f / (1.0f + exp(-x));
}

kernel void bpnn_layerforward_ocl(global float* input_ocl,
                                   global float* output_hidden_ocl,
                                   global float* input_hidden_ocl,
                                   global float* hidden_partial_sum,
                                   local float* local_sum,
                                   local float* local_weights,
                                   const int in,
                                   const int hid)
{
    int j = get_global_id(1);
    int k = get_global_id(0);
    int block_id = get_group_id(1);

    if (j >= hid + 1 || k >= in + 1)
        return;

    int local_idx = get_local_id(0) * BLOCK_SIZE + get_local_id(1);

    if (k == 0)
    {
        local_sum[local_idx] = 0.0f;
    }

    if (j >= 1 && k <= in)
    {
        float weight = input_hidden_ocl[k * (hid + 1) + j];
        float input_val = input_ocl[k];
        local_sum[local_idx] += weight * input_val;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    if (k == 0 && j >= 1)
    {
        float sum = 0.0f;
        for (int i = 0; i < BLOCK_SIZE; i++)
        {
            sum += local_sum[i * BLOCK_SIZE + j - 1];
        }

        if (block_id == 0)
        {
            sum += input_hidden_ocl[0 * (hid + 1) + j];
        }

        hidden_partial_sum[block_id * hid + j - 1] = sum;
    }
}

kernel void bpnn_adjust_weights_ocl(global float* hidden_delta_ocl,
                                     const int hid,
                                     global float* input_ocl,
                                     const int in,
                                     global float* input_hidden_ocl,
                                     global float* input_prev_weights_ocl)
{
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= hid + 1 || k >= in + 1)
        return;

    if (j >= 1)
    {
        float delta = hidden_delta_ocl[j];
        float ly = (k == 0) ? 1.0f : input_ocl[k];
        float oldw = input_prev_weights_ocl[k * (hid + 1) + j];

        float new_dw = (ETA * delta * ly) + (MOMENTUM * oldw);

        input_hidden_ocl[k * (hid + 1) + j] += new_dw;
        input_prev_weights_ocl[k * (hid + 1) + j] = new_dw;
    }
}
